#!/usr/bin/env python3
"""
Bug #1306: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['fusion', 'gemm_sigmoid'], ['broadcast', 'cumsum_last_axis'], ['branch', 'add_layernorm'], ['broadcast', 'mul_add_relu'], ['branch', 'gated_linear_branch'], ['branch', 'residual_add_relu']]
Dependencies: numpy jax
Run         : python unique_1306.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64, 64])
_w1 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w2 = np.frombuffer(bytes.fromhex("0000803f"), dtype=np.float32).reshape([1])
_w3 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 64])
_w4 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w5 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w6 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 64])
_w7 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 64])
_w8 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64, 64])
_w9 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64, 64])
_w10 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w11 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 64])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 64])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_gemm_gm = np.float32(1.0) * jnp.matmul(x, jnp.swapaxes(_w0, -1, -2)) + np.float32(1.0) * _w1
    n0_gemm_out = (np.float32(1.0) / (np.float32(1.0) + jnp.exp(-n0_gemm_gm)))
    n100_cs_out = jnp.cumsum(n0_gemm_out, axis=int(_w2.flat[0]))
    n200_aln_add = n100_cs_out + _w3
    n200_aln_out = (((lambda _x: (lambda _m, _v: (_x - _m) / jnp.sqrt(_v + np.float32(9.999999747378752e-06)))(jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True), jnp.mean((_x - jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True))**2, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True)))(n200_aln_add)) * _w4) + _w5
    n300_mar_mul = n200_aln_out * _w6
    n300_mar_add = n300_mar_mul + _w7
    n300_mar_out = jnp.maximum(n300_mar_add, np.float32(0.0))
    n400_glb_g1 = np.float32(1.0) * jnp.matmul(n300_mar_out, jnp.swapaxes(_w8, -1, -2)) + np.float32(1.0) * _w10
    n400_glb_g2 = np.float32(1.0) * jnp.matmul(n300_mar_out, jnp.swapaxes(_w9, -1, -2)) + np.float32(1.0) * _w10
    n400_glb_sig = (np.float32(1.0) / (np.float32(1.0) + jnp.exp(-n400_glb_g2)))
    n400_glb_out = n400_glb_g1 * n400_glb_sig
    n500_rarelu_add = n400_glb_out + _w11
    n500_rarelu_out = jnp.maximum(n500_rarelu_add, np.float32(0.0))
    return jnp.asarray(n500_rarelu_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
